const Header = ({ props }) => {
  return (
    <div>
      <h1>{props.name}</h1>
    </div>
  )
}
const Part = (props) => {
  return (
    <div>
      <p>
        {props.part.name}
        {props.part.exercises}

      </p>
    </div>
  );
}

const Content = (props) => {
  return (
    <div>

      <Part part={props.part[0]} />
      <Part part={props.part[1]} />
      <Part part={props.part[2]} />

    </div>
  );

}

const Total = (props) => {
  return (
    <p>Number of excercises: {props.part[0].exercise + props.part[1].exercise + props.part[2].exercise}</p>

  );

}


const App = () => {
  const course = {
    name: 'Half Stack application development',
    parts: [{
      name: 'Fundamentals of React',
      exercise:  10

    },

    {
  name: 'Using props to pass data',
  exercise : 7


    }, 
    {
      name:  'State of a component',
      excercise : 14

    }]
  }

  return(
    <div>
       <Header name={course.name} />

       <Content parts = {course.parts} />

      <Total parts = {course.parts}  />
    </div >
  )
}

export default App
